    get sortable() {
        return this._sortable;
    }
    set sortable(value) {
        this._sortable = value;
        this.updateElementClasses();
    }
    @api
    getDomHeight() {
        const child = this.template.querySelector('.slds-hyphenate');
        if (child) {
            return child.offsetHeight;
        }
        return '';
    }
    @api
    getDomWidth() {
        const { child } = this.refs;
        if (child) {
            return child.offsetWidth;
        }
        return '';
    }
